class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int distinctSequences(int n) {
        long[][] dp = new long[n + 1][7];
        for (int i = 1; i <= 6; i++) {
            dp[1][i] = 1;
        }
        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= 6; j++) {
                for (int k = 1; k <= 6; k++) {
                    if (gcd(j, k) == 1 && (i == 2 || dp[i - 2][j] == 0 || j != k)) {
                        dp[i][k] = (dp[i][k] + dp[i - 1][j]) % MOD;
                    }
                }
            }
        }
        long res = 0;
        for (int i = 1; i <= 6; i++) {
            res = (res + dp[n][i]) % MOD;
        }
        return (int) res;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}

